CREATE TABLE system_control_test_results
(
	id serial,
	organization_id integer NOT NULL,
	system_id integer NOT NULL,
	assessment_weight double precision,
	CONSTRAINT pk_system_control_test_results PRIMARY KEY (id)
	, CONSTRAINT fk_system_control_test_results_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_system_control_test_results_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_system_control_test_result_to_organization ON system_control_test_results (organization_id);
CREATE INDEX i_system_control_test_result_to_system ON system_control_test_results (system_id);
